@startuml
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #f0f0f0
  BorderColor black
  ArrowColor black
  AttributeFontColor black
  AttributeIconColor red
}

class Settings {
  + key
  + value
}

class InputSensor {
  + name
  + temperature
  + humidity
}

class InputWeatherstation {
  + name
  + temperature
  + humidity
  + wind_speed
  + rain_amount
  + raining
}

class InputSwitch {
  + name
  + image
  + x
  + y
  + width
  + height
  + state
}

class InputSolarpanel {
  + name
  + power
}

class InputWindow {
  + name
  + closed
}

class OutputTrigger {
  + name
  + state
}

class SwitchState {
  + on
  + off
  + auto
}

InputSwitch -- SwitchState

@enduml
